#include<bits/stdc++.h>
using namespace std;
long long b[101];
int main()
{
    long long n;
    scanf("%lld",&n);
    for(long long i=1;i<=n;i++)
    {
        long long x;
        scanf("%lld",&x);
        for(long long j=50;j>=0;j--)
        {
            if(x&(1ll<<j))
            {
                if(b[j]==0)
                {
                    b[j]=x;
                }
                x^=b[j];
            }
        }
    }
    long long ans=0;
    for(long long i=50;i>=0;i--)
    {
        if(!(ans&(1ll<<i)))
        {
            ans^=b[i];
        }
    }
    printf("%lld",ans);
    return 0;
}
